// Entidad Customer actualizada con relación a productos
package com.paymentchange.customer.entities;

import jakarta.persistence.*;
import lombok.Data;
import java.util.ArrayList;
import java.util.List;

@Data
@Entity
public class Customer {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private String name;
    private String phoneNumber;

    // Relación con productos mediante IDs
    @ElementCollection
    @CollectionTable(
        name = "customer_products",
        joinColumns = @JoinColumn(name = "customer_id")
    )
    @Column(name = "product_id")
    private List<Long> productIds = new ArrayList<>();
}

/* Tabla generada automáticamente:
customer_products
- customer_id (FK a customer)
- product_id (Long, ID de producto en otro microservicio)
*/
